      background: var(--sidebar-bg);
      padding: 1rem 2rem;
      display: flex;
      justify-content: space-between;
      align-items: center;
      border-bottom: 1px solid var(--border-color);
    }

    .header-left {
      display: flex;
      align-items: center;
      gap: 3rem;
    }

    .logo {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      font-size: 1.25rem;
      font-weight: 600;
    }

    .icon {
      font-size: 1.5rem;
    }

    .nav-links {
      display: flex;
      gap: 2rem;
    }

    .nav-links a {
      color: var(--text-secondary);
      text-decoration: none;
      transition: color 0.3s;
    }

    .nav-links a:hover {
      color: var(--text-primary);
    }

    .header-right {
      display: flex;
      align-items: center;
      gap: 1rem;
    }

    .search-bar {
      display: flex;
      background: var(--bg-tertiary);
      border-radius: 6px;
      overflow: hidden;
    }

    .search-bar input {
      background: transparent;
      border: none;
      padding: 0.5rem 1rem;
      color: var(--text-primary);
      width: 300px;
    }

    .search-bar button {
      background: transparent;
      border: none;
      padding: 0.5rem 1rem;
      cursor: pointer;
    }

    .filter-select {
      background: var(--bg-tertiary);
      border: 1px solid var(--border-color);
      color: var(--text-primary);
      padding: 0.5rem;
      border-radius: 6px;
    }

    .cart-icon, .user-icon {
      font-size: 1.5rem;
      position: relative;
      cursor: pointer;
    }

    .badge {
      position: absolute;
      top: -5px;
      right: -5px;
      background: var(--error);
      color: white;
      border-radius: 50%;
      width: 20px;
      height: 20px;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 0.75rem;
    }

    .main-content {
      display: flex;
    }

    .sidebar {
      width: 250px;
      background: var(--sidebar-bg);
      min-height: calc(100vh - 70px);
      padding: 2rem 1rem;
      border-right: 1px solid var(--border-color);
    }

    .category-list {
      display: flex;
      flex-direction: column;
      gap: 0.5rem;
    }

    .category-item {
      padding: 0.75rem 1rem;
      cursor: pointer;
      border-radius: 6px;
      transition: all 0.3s;
      color: var(--text-secondary);
    }

    .category-item:hover {
      background: var(--bg-tertiary);
      color: var(--text-primary);
    }

    .category-item.active {
      background: var(--accent-primary);
      color: white;
    }

    .content {
      flex: 1;
      padding: 2rem;
    }

    .product-section {
