      background: var(--card-bg);
      border-radius: 8px;
      overflow: hidden;
      transition: transform 0.3s;
      cursor: pointer;
    }

    .product-card:hover {
      transform: translateY(-4px);
    }

    .product-image {
      width: 100%;
      height: 350px;
      object-fit: cover;
    }

    .product-info {
      padding: 1rem;
    }

    .product-title {
      font-size: 1.1rem;
      font-weight: 600;
      margin-bottom: 0.5rem;
    }

    .product-author {
      color: var(--text-secondary);
      font-size: 0.9rem;
      margin-bottom: 0.5rem;
    }

    .product-description {
      color: var(--text-muted);
      font-size: 0.85rem;
      margin-bottom: 0.5rem;
    }

    .product-format {
      color: var(--text-secondary);
      font-size: 0.85rem;
      margin-bottom: 0.25rem;
    }

    .product-tags {
      color: var(--accent-primary);
      font-size: 0.85rem;
      margin-bottom: 0.75rem;
    }

    .product-footer {
      display: flex;
      justify-content: space-between;
      align-items: center;
    }

    .product-price {
      font-size: 1.25rem;
      font-weight: 600;
      color: var(--text-primary);
    }

    .delivery-info {
      font-size: 0.75rem;
      color: var(--text-muted);
    }
  `]
})
export class HomeComponent implements OnInit {
  private productService = inject(ProductService);

  searchQuery = '';
  cartCount = 0;
  selectedCategory = 'all';
  
  categories = [
    'Romance', 'Mystery', 'Science Fiction', 'Fantasy', 'Historical',
    'Self-help', 'Memoir', 'Travel', 'Horror', "Children's", 'Young Adult',
    'Comics & Graphic Novels', 'Poetry', 'Drama', 'Science', 'Philosophy',
    'Religion', 'Language Learning'
  ];

  recommendedProducts: Product[] = [];
  bestsellers: Product[] = [];
  newLaunches: Product[] = [];

  ngOnInit() {
    this.loadProducts();
  }

  loadProducts() {
    // Load recommended products
    this.productService.getRecommendations().subscribe(
      response => this.recommendedProducts = response.data
    );

    // Load bestsellers
    this.productService.getProducts({ sort: 'popular', limit: 6 }).subscribe(
      response => this.bestsellers = response.data
    );

    // Load new launches
    this.productService.getProducts({ sort: 'newest', limit: 6 }).subscribe(
      response => this.newLaunches = response.data
    );
  }

  selectCategory(category: string) {
    this.selectedCategory = category;
    // Load products for selected category
  }

  search() {
    // Implement search
  }
}

